/* test_fmu.c — generated by sml2c.
 *
 * Smoke test: instantiate the FMU, transition through Init,
 * read back every parameter through fmi3Get*, free.
 * Exit code 0 = pass, non-zero = fail.
 *
 * Linked directly against the FMU library (no dlopen) to keep
 * the test plumbing small.  fmi3 functions are name-prefixed
 * with Engine_ via FMI3_FUNCTION_PREFIX, so we set it before
 * including fmi3Functions.h.                                */
#define FMI3_FUNCTION_PREFIX Engine_
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "fmi3Functions.h"
#include "model.h"

/* Captures the most recent logger message so the violation
 * test can assert the constraint name appeared in the log. */
static char logBuf[1024];
static fmi3Status logStatus = fmi3OK;

static void onLog(fmi3InstanceEnvironment env, fmi3Status status,
                  fmi3String category, fmi3String message) {
    (void)env;
    logStatus = status;
    if (message) snprintf(logBuf, sizeof(logBuf), "%s", message);
    fprintf(stderr, "[%d %s] %s\n", (int)status,
            category ? category : "", message ? message : "");
}

int main(void) {
    fmi3Instance c = fmi3InstantiateCoSimulation(
        "test", "", NULL,
        fmi3False, fmi3False, fmi3False, fmi3False,
        NULL, 0, NULL, onLog, NULL);
    if (!c) { fprintf(stderr, "instantiate failed\n"); return 1; }

    if (fmi3EnterInitializationMode(c, fmi3False, 0.0, 0.0,
                                   fmi3False, 0.0) != fmi3OK) {
        fprintf(stderr, "enter init failed\n"); return 2;
    }
    if (fmi3ExitInitializationMode(c) != fmi3OK) {
        fprintf(stderr, "exit init failed\n"); return 3;
    }

    int errors = 0;
    {
        fmi3ValueReference vr = 1;
        fmi3Float64 val = 0;
        if (fmi3GetFloat64(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get force failed\n"); errors++;
        } else {
            printf("force = %g\n", (double)val);
        }
    }
    {
        fmi3ValueReference vr = 2;
        fmi3Float64 val = 0;
        if (fmi3GetFloat64(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get velocity failed\n"); errors++;
        } else {
            printf("velocity = %g\n", (double)val);
        }
    }
    {
        fmi3ValueReference vr = 3;
        fmi3Float64 val = 0;
        if (fmi3GetFloat64(c, &vr, 1, &val, 1) != fmi3OK) {
            fprintf(stderr, "get power failed\n"); errors++;
        } else {
            printf("power = %g\n", (double)val);
        }
    }

    fmi3Boolean evNeed = fmi3False, term = fmi3False, early = fmi3False;
    fmi3Float64 lastT = 0.0;
    if (fmi3DoStep(c, 0.0, 0.01, fmi3False,
                   &evNeed, &term, &early, &lastT) != fmi3OK) {
        fprintf(stderr, "DoStep failed\n"); errors++;
    }

    /* v0.26 constraint-violation re-init.  We expect ExitInit
     * to return fmi3Error and the logger to have received a
     * per-constraint failure message.  We use a hugely
     * negative value as the violator — for the FmuConstraints
     * fixture this fails `force > 0.0`. */
    if (fmi3Reset(c) != fmi3OK) { errors++; }
    if (fmi3EnterInitializationMode(c, fmi3False, 0.0, 0.0,
                                   fmi3False, 0.0) != fmi3OK) {
        fprintf(stderr, "re-enter init failed\n"); errors++;
    }
    {
        fmi3ValueReference vr = 1;
        fmi3Float64 bad = -999999.0;
        if (fmi3SetFloat64(c, &vr, 1, &bad, 1) != fmi3OK) {
            fprintf(stderr, "set violator failed\n"); errors++;
        }
    }
    logBuf[0] = '\0';
    fmi3Status rc = fmi3ExitInitializationMode(c);
    if (rc == fmi3OK) {
        fprintf(stderr,
            "violation NOT detected: ExitInit returned fmi3OK\n");
        errors++;
    } else {
        if (logBuf[0] == '\0') {
            fprintf(stderr,
                "violation logger NOT called\n");
            errors++;
        } else {
            printf("violation captured: %s\n", logBuf);
        }
    }

    if (fmi3Terminate(c) != fmi3OK) errors++;
    fmi3FreeInstance(c);
    return errors == 0 ? 0 : 4;
}
